import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import BusTrendChart from "./BusTrendChart"; // Corrected import

function MapComponent() {
  const [buses, setBuses] = useState([]);

  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://127.0.0.1:8000/buses");
        const data = await response.json();
        setBuses(data);
      } catch (error) {
        console.error("Error fetching buses:", error);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // fetch every 2 mins
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={{ display: "flex" }}>
      <MapContainer
        center={[40.7128, -74.006]} // NYC coordinates
        zoom={12}
        style={{ height: "600px", width: "70%" }}
      >
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          attribution="&copy; OpenStreetMap contributors"
        />
        {buses.map((bus) => (
          <CircleMarker
            key={bus.id + "_" + bus.timestamp} // unique key
            center={[bus.lat, bus.lon]}
            radius={6}
            color={
              bus.status === "normal"
                ? "green"
                : bus.status === "ghost"
                ? "red"
                : "orange"
            }
          />
        ))}
      </MapContainer>

      <div style={{ width: "30%", padding: "10px" }}>
        <BusTrendChart data={buses} />
      </div>
    </div>
  );
}

export default MapComponent;
